renderScript:
function(wrap, spec) {
  if (!wrap.style.height) wrap.style.height = '360px';
  const ec = echarts.init(wrap);
  ec.setOption({
    backgroundColor: '#ffffff',
    series: [{
      type: 'gauge',
      min: spec.min !== undefined ? spec.min : 0,
      max: spec.max !== undefined ? spec.max : 100,
      splitNumber: 5,
      radius: '80%',
      axisLine: { lineStyle: { width: 18, color: [[0.3,'#e05c5c'],[0.7,'#f0a840'],[1,'#4caf50']] } },
      pointer: { itemStyle: { color: 'auto' } },
      axisTick: { distance: -22, length: 8, lineStyle: { color: '#fff', width: 2 } },
      splitLine: { distance: -28, length: 18, lineStyle: { color: '#fff', width: 3 } },
      axisLabel: { color: 'inherit', distance: 28, fontSize: 12 },
      detail: { valueAnimation: true, formatter: '{value}' + (spec.unit || ''), color: 'inherit', fontSize: 22, offsetCenter: [0, '60%'] },
      title: { offsetCenter: [0, '90%'], fontSize: 14 },
      data: [{ value: spec.value, name: spec.title || '' }]
    }]
  });
  window.addEventListener('resize', () => ec.resize());
}
